import { Component, computed, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { ActivatedRoute } from '@angular/router';
import { AuthService } from '../../../core/services/auth.service';
import { SiteviewService } from '../../../core/services/siteview.service';
import { Task } from '../../../core/models/siteview.models';

interface GanttRow {
  task: Task;
  phaseName: string;
  y: number;
  x: number;
  w: number;
  fillW: number;
}
interface GanttDep {
  path: string;
}
interface AxisTick {
  x: number;
  label: string;
}
interface GanttLayout {
  width: number;
  height: number;
  labelW: number;
  rows: GanttRow[];
  deps: GanttDep[];
  ticks: AxisTick[];
  todayX: number | null;
}

const LABEL_W = 180;
const PLOT_W = 720;
const ROW_H = 46;
const TOP = 44;
const BAR_H = 22;
const DAY = 86_400_000;

@Component({
  selector: 'app-gantt',
  standalone: true,
  imports: [CommonModule, FormsModule],
  templateUrl: './gantt.component.html',
  styleUrl: './gantt.component.css',
})
export class GanttComponent {
  private readonly projectId = this.route.parent?.snapshot.paramMap.get('id') ?? '';
  private readonly refresh = signal(0);
  readonly selectedTaskId = signal<string | null>(null);

  readonly tasks = computed(() => {
    this.refresh();
    const phases = this.sv.phasesForProject(this.projectId);
    const order = new Map(phases.map((p, i) => [p.id, i]));
    return this.sv
      .tasksForProject(this.projectId)
      .slice()
      .sort((a, b) => {
        const pa = order.get(a.phaseId) ?? 0;
        const pb = order.get(b.phaseId) ?? 0;
        if (pa !== pb) return pa - pb;
        return a.startsOn.localeCompare(b.startsOn);
      });
  });

  readonly layout = computed<GanttLayout>(() => {
    const tasks = this.tasks();
    const phases = this.sv.phasesForProject(this.projectId);
    const phaseName = new Map(phases.map((p) => [p.id, p.name]));

    if (tasks.length === 0) {
      return { width: LABEL_W + PLOT_W, height: TOP + 40, labelW: LABEL_W, rows: [], deps: [], ticks: [], todayX: null };
    }

    const starts = tasks.map((t) => new Date(t.startsOn).getTime());
    const ends = tasks.map((t) => new Date(t.endsOn).getTime());
    const min = Math.min(...starts);
    const max = Math.max(...ends);
    const span = Math.max(DAY, max - min);
    const x = (ms: number) => LABEL_W + ((ms - min) / span) * PLOT_W;

    const rowIndex = new Map(tasks.map((t, i) => [t.id, i]));
    const rows: GanttRow[] = tasks.map((t, i) => {
      const xs = x(new Date(t.startsOn).getTime());
      const xe = x(new Date(t.endsOn).getTime());
      const w = Math.max(6, xe - xs);
      return {
        task: t,
        phaseName: phaseName.get(t.phaseId) ?? '',
        y: TOP + i * ROW_H,
        x: xs,
        w,
        fillW: (w * Math.min(100, Math.max(0, t.progressPct))) / 100,
      };
    });

    const deps: GanttDep[] = [];
    for (const t of tasks) {
      if (!t.dependsOnTaskId) continue;
      const from = rowIndex.get(t.dependsOnTaskId);
      const to = rowIndex.get(t.id);
      if (from == null || to == null) continue;
      const fr = rows[from];
      const tr = rows[to];
      const x1 = fr.x + fr.w;
      const y1 = fr.y + BAR_H / 2;
      const x2 = tr.x;
      const y2 = tr.y + BAR_H / 2;
      const midX = Math.max(x1 + 14, x2 - 14);
      deps.push({ path: `M ${x1} ${y1} L ${midX} ${y1} L ${midX} ${y2} L ${x2 - 6} ${y2}` });
    }

    // month ticks
    const ticks: AxisTick[] = [];
    const d = new Date(min);
    d.setDate(1);
    d.setMonth(d.getMonth() + 1);
    while (d.getTime() < max) {
      ticks.push({
        x: x(d.getTime()),
        label: d.toLocaleDateString('en-US', { month: 'short' }),
      });
      d.setMonth(d.getMonth() + 1);
    }

    const now = Date.now();
    const todayX = now >= min && now <= max ? x(now) : null;

    return {
      width: LABEL_W + PLOT_W,
      height: TOP + tasks.length * ROW_H + 10,
      labelW: LABEL_W,
      rows,
      deps,
      ticks,
      todayX,
    };
  });

  readonly selectedTask = computed(() =>
    this.tasks().find((t) => t.id === this.selectedTaskId()) ?? null,
  );

  constructor(
    public auth: AuthService,
    private sv: SiteviewService,
    private route: ActivatedRoute,
  ) {}

  select(id: string): void {
    this.selectedTaskId.set(this.selectedTaskId() === id ? null : id);
  }

  setProgress(taskId: string, value: number | string): void {
    this.sv.updateTaskProgress(taskId, Number(value));
    this.refresh.update((n) => n + 1);
  }

  barClass(pct: number): string {
    if (pct >= 100) return 'done';
    if (pct === 0) return 'todo';
    return 'active';
  }
}
